use std::fmt;

#[derive(Debug, Clone)]
enum TaskState {
    Idle,
    Running { duration_seconds: u64 },
    Finished
}

impl fmt::Display for TaskState {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            TaskState::Idle => write!(f, "Ready to start."),
            TaskState::Running { duration_seconds } => write!(f, "Counting down for {} seconds.", duration_seconds),
            TaskState::Finished => write!(f, "Cycle complete!")
        }
    }
}

fn update_state(current: &TaskState, action: &str) -> Result<TaskState, String> {
    match (current, action) {
        (&TaskState::Idle, "start") => Ok(TaskState::Running { duration_seconds: 25 }),
        (&TaskState::Running { .. }, "pause") => Ok(TaskState::Idle),
        (&TaskState::Finished, "reset") => Ok(TaskState::Idle),
        (_, _) => Err(format!("Cannot perform action '{}' in the current state.", action)),
    }
}

fn main() {
    let mut state = TaskState::Idle;
    println!("Initial State: {}", state);

    match update_state(&state, "start") {
        Ok(new_state) => { state = new_state; println!("Updated State: {}", state); }
        Err(e) => eprintln!("Error updating state: {}", e),
    }

    match update_state(&state, "pause") {
        Ok(new_state) => { state = new_state; println!("Updated State: {}", state); }
        Err(e) => eprintln!("Error updating state: {}", e),
    }

    match update_state(&state, "unknown_action") {
        Ok(new_state) => { state = new_state; println!("Updated State: {}", state); }
        Err(e) => eprintln!("Successfully caught error: {}", e),
    }
}

use std::fs::File;
use std::io::{self, BufRead, BufReader};

struct Record {
    line_number: usize,
    content: String,
}

fn process_file(path: &str) -> Result<Vec<Record>, io::Error> {
    let file = File::open(path)?;
    let reader = BufReader::new(file);

    let mut records = Vec::new();
    for (i, line_result) in reader.lines().enumerate() {
        let line_number = i + 1;
        match line_result {
            Ok(line) => records.push(Record { line_number, content: line }),
            Err(e) => return Err(e),
        }
    }
    Ok(records)
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let path = "test_data.txt";
    std::fs::write(path, "First line datanSecond line datanT third line data");

    match process_file(path) {
        Ok(records) => {
            println!("Successfully processed {} records.", records.len());
        }
        Err(e) => {
            eprintln!("Failed to read or process the file: {}", e);
        }
    }
    Ok(())
}

use core::result::Result;

struct GpioController {
    output_registers: [u32; 2],
}

impl GpioController {
    fn new() -> Self {
        GpioController { output_registers: [0, 0] }
    }

    fn write_register(&mut self, index: usize, value: u32) -> Result<(), &'static str> {
        if index >= self.output_registers.len() {
            return Err("Invalid GPIO index");
        }
        self.output_registers[index] = value;
        Ok(())
    }

    fn handle_interrupt(&mut self, status: u32) -> Result<(), &'static str> {
        if (status & 0x1) == 0 {
            return Err("Interrupt source not active");
        }

        let initial_state = self.output_registers[0];
        self.write_register(0, initial_state | 0x0F)?; 

        match status & 0xF {
            0b0001 => { 
                self.write_register(1, self.output_registers[1] | 0x01)?;
                Ok(()) 
            },
            0b1000 => { 
                let new_value = self.output_registers[0].wrapping_add(1); 
                self.write_register(0, new_value)?; 
                Ok(()) 
            }
            _ => Err("Unrecognized interrupt mask"),
        }
    }
}

fn main() {
    let mut gpio = GpioController::new();
    match gpio.handle_interrupt(0x1) {
        Ok(_) => println!("Success handling interrupt."),
        Err(e) => println!("Error: {}", e),
    }
}

use std::collections::HashMap;

#[derive(Debug)]
enum ImageFormat {
    Jpeg,
    Png,
    Unknown(String),
}

struct ImageAnalyzer {
    metadata: HashMap<String, ImageFormat>,
}

impl ImageAnalyzer {
    fn new() -> Self {
        ImageAnalyzer {
            metadata: HashMap::new(),
        }
    }

    fn analyze_file(&mut self, filename: &str) -> Result<(), std::io::Error> {
        if filename.contains(".jpg") {
            self.metadata.insert(filename.to_string(), ImageFormat::Jpeg);
            println!("Successfully analyzed JPEG: {}", filename);
            Ok(())
        } else if filename.contains(".png") {
            self.metadata.insert(filename.to_string(), ImageFormat::Png);
            println!("Successfully analyzed PNG: {}", filename);
            Ok(())
        } else {
            Err(std::io::Error::new(std::io::ErrorKind::InvalidInput, "Unspported file type"))
        }
    }

    fn process_batch(&mut self, filenames: &[&str]) -> usize {
        let mut success_count = 0;
        for &filename in filenames.iter() {
            if let Ok(_) = self.analyze_file(filename) {
                success_count += 1;
            } else {
                println!("Skipping file due to error: {}", filename);
            }
        }
        success_count
    }
}

fn main() {
    let mut analyzer = ImageAnalyzer::new();
    let files_to_check = &["layer1.jpg", "logo.png", "broken_file.dat", "background.jpg"];
    let count = analyzer.process_batch(files_to_check);
    println!("nFinished processing. Total successful analyses: {}", count);
}

use std::fs::File;
use std::io::{self, Read};

struct VoxelMesh {
    vertices: Vec<f32>,
}
impl VoxelMesh {
    fn new() -> Self {
        VoxelMesh { vertices: Vec::new() }
    }

    fn process_data(path: &str) -> io::Result<Self> {
        let mut file = File::open(path)?;
        let mut buffer_bytes = Vec::new();
        file.read_to_end(&mut buffer_bytes)?;

        let mut mesh = VoxelMesh::new();
        mesh.vertices.extend(buffer_bytes.into_iter().map(|b| b as f32));
        Ok(mesh)
    }
}

fn main() {
    match VoxelMesh::process_data("non_existent_file.dat") {
        Ok(mesh) => println!("Successfully loaded mesh with {} bytes of data.", mesh.vertices.len()),
        Err(e) => eprintln!("Failed to load mesh: {}", e)
    }
}
